Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
                                                bool FoldWithMultiUse) {
  // Don't modify shared select instructions unless set FoldWithMultiUse
  if (!SI->hasOneUse() && !FoldWithMultiUse)
    return nullptr;

  Value *TV = SI->getTrueValue();
  Value *FV = SI->getFalseValue();

  // Bool selects with constant operands can be folded to logical ops.
  if (SI->getType()->isIntOrIntVectorTy(1))
    return nullptr;

  // Test if a FCmpInst instruction is used exclusively by a select as
  // part of a minimum or maximum operation. If so, refrain from doing
  // any other folding. This helps out other analyses which understand
  // non-obfuscated minimum and maximum idioms. And in this case, at
  // least one of the comparison operands has at least one user besides
  // the compare (the select), which would often largely negate the
  // benefit of folding anyway.
  if (auto *CI = dyn_cast<FCmpInst>(SI->getCondition())) {
    if (CI->hasOneUse()) {
      Value *Op0 = CI->getOperand(0), *Op1 = CI->getOperand(1);
      if ((TV == Op0 && FV == Op1) || (FV == Op0 && TV == Op1))
        return nullptr;
    }
  }

  // Handle the specific case: fcmp ord -> select (x, 0) -> fcmp oeq with constant
  if (auto *FCmp1 = dyn_cast<FCmpInst>(&Op)) {
    if (FCmp1->getPredicate() == FCmpInst::FCMP_ORD && isa<ConstantFP>(FV) &&
        cast<ConstantFP>(FV)->isZero() && FCmp1->getOperand(1)->isNullValue()) {
      if (auto *FCmp2 = dyn_cast<FCmpInst>(SI->getCondition()))
        if (FCmp2->getPredicate() == FCmpInst::FCMP_OEQ && isa<ConstantFP>(FCmp2->getOperand(1))) {
          // The select chooses between %x and 0.0, guarded by ord(%x, 0.0).
          // Then we compare the result for equality with a constant (e.g. 1.0).
          // If the select returns 0.0 when %x is NaN, and 0.0 != C (e.g. C = 1.0),
          // then the result of the outer fcmp is equivalent to fcmp oeq %x, C.
          ConstantFP *C = cast<ConstantFP>(FCmp2->getOperand(1));
          if (!C->isZero()) {  // ensure that C != 0 to allow simplification
            Value *OrigVal = FCmp2->getOperand(0);
            if (OrigVal == SI) {
              // We can now fold: fcmp oeq (select (ord %x, 0), %x, 0), C  -->  fcmp oeq %x, C
              // because if %x is NaN, ord is false, select returns 0, and 0 != C (if C != 0)
              // So only when %x is not NaN and %x == C does the original return true.
              // That is exactly what fcmp oeq %x, C computes.
              Value *X = FCmp1->getOperand(0);
              Type *Ty = X->getType();
              Value *CVal = ConstantFP::get(Ty, C->getValueAPF());
              FCmpInst::Predicate Pred = FCmp2->getPredicate();
              Value *NewCmp = new FCmpInst(Op.getParent()->getParent()->front().getFirstNonPHI(),
                                           Pred, X, CVal);
              this->InsertNewInstBefore(cast<Instruction>(NewCmp), Op.getIterator());
              return cast<Instruction>(NewCmp);
            }
          }
        }
    }
  }

  // Make sure that one of the select arms folds successfully.
  Value *NewTV = simplifyOperationIntoSelectOperand(Op, SI, /*IsTrueArm=*/true);
  Value *NewFV =
      simplifyOperationIntoSelectOperand(Op, SI, /*IsTrueArm=*/false);
  if (!NewTV && !NewFV)
    return nullptr;

  // Create an instruction for the arm that did not fold.
  if (!NewTV)
    NewTV = foldOperationIntoSelectOperand(Op, SI, TV, *this);
  if (!NewFV)
    NewFV = foldOperationIntoSelectOperand(Op, SI, FV, *this);
  return SelectInst::Create(SI->getCondition(), NewTV, NewFV, "", nullptr, SI);
}

